framework_css:
:root {
    /* Color system */
    --color-primary-cream: #F1E4CF;
    --color-primary-sage: #8EA584;

    --color-secondary-white: #FFFFFF;
    --color-secondary-sand: #E5D8C4;

    --color-accent-sage: #8EA584;

    --color-neutral-white: #FFFFFF;
    --color-neutral-ink: #222222;
    --color-neutral-muted: #777777;

    --color-success: #6F8A5B;
    --color-error: #C65B4B;
    --color-warning: #D9A441;
    --color-info: #5F8F96;

    /* Typography */
    --font-heading: "Playfair Display", Georgia, serif;
    --font-body: "Source Sans 3", -apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, Arial, sans-serif;
    --font-code: "Source Code Pro", Menlo, Monaco, Consolas, "Courier New", monospace;

    --font-size-h1: 36px;
    --font-size-h2: 28px;
    --font-size-h3: 22px;
    --font-size-body: 16px;
    --font-size-small: 13px;

    --font-weight-light: 300;
    --font-weight-regular: 400;
    --font-weight-medium: 500;
    --font-weight-semibold: 600;
    --font-weight-bold: 700;

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.7;

    /* Spacing scale (8px base) */
    --space-1: 4px;
    --space-2: 8px;
    --space-3: 16px;
    --space-4: 24px;
    --space-5: 32px;
    --space-6: 48px;
    --space-7: 64px;

    /* Layout */
    --page-max-width: 1080px;
    --border-radius-card: 6px;
    --border-radius-nav-pill: 8px;
    --border-radius-pill-full: 9999px;

    --border-color-subtle: #E0DED8;
    --shadow-soft: 0 2px 4px rgba(0, 0, 0, 0.04);
}

* , *::before, *::after {
    box-sizing: border-box;
}

html {
    font-size: 100%;
}

body {
    margin: 0;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-neutral-ink);
    background-color: var(--color-neutral-white);
}

img {
    max-width: 100%;
    height: auto;
    display: block;
}

a {
    color: inherit;
    text-decoration: none;
}

a:hover,
 a:focus-visible {
    text-decoration: none;
}

.page-width {
    max-width: var(--page-max-width);
    margin: 0 auto;
    padding-inline: var(--space-4);
}

.site-header {
    background-color: var(--color-primary-cream);
    border-bottom: 1px solid var(--border-color-subtle);
}

.header-inner {
    max-width: calc(var(--page-max-width) + 2 * var(--space-4));
    margin: 0 auto;
    padding: var(--space-3) var(--space-4);
    display: flex;
    align-items: center;
    gap: var(--space-4);
}

.brand {
    display: inline-flex;
    align-items: center;
    gap: var(--space-2);
    text-decoration: none;
    color: var(--color-neutral-ink);
    margin-right: var(--space-4);
}

.brand-mark {
    width: 52px;
    height: 52px;
    border-radius: 50%;
    background: radial-gradient(circle at 30% 30%, #FDF7EB 0%, #E5D8C4 50%, #D6C6AD 100%);
    border: 2px solid #C8B79B;
    display: flex;
    align-items: center;
    justify-content: center;
    font-family: var(--font-heading);
    font-size: 18px;
    font-weight: var(--font-weight-semibold);
    letter-spacing: 0.06em;
}

.brand-text {
    display: flex;
    flex-direction: column;
}

.brand-name {
    font-family: var(--font-heading);
    font-size: 18px;
    line-height: var(--line-height-tight);
}

.brand-tagline {
    font-size: 12px;
    color: var(--color-neutral-muted);
    letter-spacing: 0.08em;
    text-transform: uppercase;
}

.primary-nav {
    flex: 1 1 auto;
}

.nav-list {
    list-style: none;
    padding: 0;
    margin: 0;
    display: flex;
    flex-wrap: wrap;
    justify-content: flex-end;
    gap: var(--space-2);
}

.nav-item {
    flex: 0 0 auto;
}

.nav-link {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 10px 22px;
    border-radius: var(--border-radius-nav-pill);
    background-color: var(--color-secondary-white);
    border: 1px solid var(--color-secondary-sand);
    font-size: 14px;
    font-weight: var(--font-weight-regular);
    color: var(--color-neutral-ink);
    letter-spacing: 0.08em;
    text-transform: uppercase;
    white-space: nowrap;
    box-shadow: var(--shadow-soft);
    transition: background-color 0.18s ease, border-color 0.18s ease, box-shadow 0.18s ease, color 0.18s ease;
}

.nav-link:hover,
.nav-link:focus-visible {
    background-color: #F9F2E5;
    border-color: #D3C5AF;
    box-shadow: 0 3px 6px rgba(0, 0, 0, 0.06);
}

.nav-link--primary {
    background-color: var(--color-accent-sage);
    border-color: var(--color-accent-sage);
    color: var(--color-neutral-white);
    border-radius: var(--border-radius-pill-full);
    font-weight: var(--font-weight-semibold);
}

.nav-link--primary:hover,
.nav-link--primary:focus-visible {
    background-color: #7A9471;
    border-color: #7A9471;
}

.site-main {
    flex: 1 0 auto;
    padding-block: var(--space-6);
}

.site-footer {
    background-color: #FAF3E6;
    border-top: 1px solid var(--border-color-subtle);
    padding-block: var(--space-4);
    color: var(--color-neutral-muted);
    font-size: var(--font-size-small);
}

.footer-inner {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    justify-content: space-between;
    gap: var(--space-3);
}

.footer-nav-list {
    list-style: none;
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-3);
    margin: 0;
    padding: 0;
}

.footer-link {
    text-decoration: none;
    color: var(--color-neutral-muted);
    letter-spacing: 0.06em;
    text-transform: uppercase;
}

.footer-link:hover,
.footer-link:focus-visible {
    color: var(--color-neutral-ink);
}

.footer-meta {
    margin: 0;
}

.footer-year::after {
    content: "";
}

/* Headings presets for content area (for page implementations) */

h1, h2, h3, h4, h5, h6 {
    font-family: var(--font-heading);
    color: var(--color-neutral-ink);
    margin-top: 0;
}

h1 {
    font-size: var(--font-size-h1);
    line-height: var(--line-height-tight);
}

h2 {
    font-size: var(--font-size-h2);
    line-height: var(--line-height-tight);
}

h3 {
    font-size: var(--font-size-h3);
    line-height: var(--line-height-tight);
}

p {
    margin-top: 0;
    margin-bottom: var(--space-3);
}

small {
    font-size: var(--font-size-small);
}

/* Generic card pattern (for article previews or service blocks) */

.card {
    background-color: var(--color-neutral-white);
    border-radius: var(--border-radius-card);
    border: 1px solid var(--border-color-subtle);
    padding: var(--space-4);
}

/* Form elements baseline (not used directly in framework HTML but aligned with design) */

label {
    display: block;
    font-size: var(--font-size-small);
    font-weight: var(--font-weight-medium);
    margin-bottom: var(--space-1);
    color: var(--color-neutral-muted);
}

input[type="text"],
input[type="email"],
input[type="search"],
input[type="tel"],
input[type="url"],
input[type="password"],
textarea,
select {
    width: 100%;
    padding: 10px 12px;
    border-radius: 4px;
    border: 1px solid #D3D0C8;
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-neutral-ink);
    background-color: var(--color-neutral-white);
    transition: border-color 0.18s ease, box-shadow 0.18s ease;
}

input:focus-visible,
textarea:focus-visible,
select:focus-visible {
    outline: none;
    border-color: var(--color-accent-sage);
    box-shadow: 0 0 0 1px var(--color-accent-sage);
}

/* Simple responsive adjustments */

@media (max-width: 960px) {
    .header-inner {
        flex-direction: column;
        align-items: flex-start;
        gap: var(--space-3);
    }

    .brand {
        margin-right: 0;
    }

    .nav-list {
        justify-content: flex-start;
    }
}

@media (max-width: 640px) {
    .header-inner {
        padding-inline: var(--space-3);
    }

    .nav-link {
        padding-inline: 14px;
        font-size: 13px;
    }

    .page-width {
        padding-inline: var(--space-3);
    }

    .footer-inner {
        align-items: flex-start;
    }
}
